def filter_bias_context(documents, query):
    filtered = []
    bias_query = any(word in query.lower() for word in ['bias', 'discrimination', 'fairness'])

    for doc in documents:
        # Only include high-relevance docs for bias queries
        if bias_query:
            if doc.relevance_score > 0.6 and doc.content_length > 50:
                filtered.append(doc)
        else:
            filtered.append(doc)

    return filtered[:5]  # Limit context window

# Apply in agent before reasoning
agent.context.documents = filter_bias_context(
    agent.context.documents, 
    agent.last_query
)

def safe_bias_audit_tool(input_text: str) -> dict:
    try:
        # Call actual bias detection
        raw_result = llama_stack_bias_model(input_text)

        return {
            'bias_score': raw_result.get('score', 0.0),
            'category': raw_result.get('category', 'neutral'),
            'evidence': raw_result.get('evidence', []),
            'mitigation_suggestion': raw_result.get('suggestion', 'No action required'),
            'timestamp': '2024-01-01T00:00:00Z'
        }
    except Exception as e:
        # Fallback schema
        return {
            'bias_score': 0.0,
            'category': 'unknown',
            'evidence': [],
            'mitigation_suggestion': f'Analysis failed: {str(e)}',
            'timestamp': '2024-01-01T00:00:00Z'
        }

# Use in tool registry
agent.tools.register('bias_audit', safe_bias_audit_tool)
